INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1519, 195563, 7, 1673, '随便写写', '最近的生活有点乱乱的，整天也不知道到在做什么，刚刚才看完朋友写的文章，我横看竖看也都不敢相信那样颓废的人也有这样的文笔，看了以后，对他多少也有些了解。前几天，他刚从中国回来，还居然帮我带了一样东西，一开始我到还挺新奇问他是什么，他的答案也是我没有估计到的，原来是个护身符，还是特地去山上找什么法师开光的，听起来有那么点小感动，可惜的是。。。我是一个基督徒，不过我也不好，从头到尾都没和他说过。 那天晚上和他小聊了一会儿，这个人还真能带惊喜，没想到他回国一下，整个人都不一样了，以前从不打工，不做饭， 两个月才去干洗店洗一下衣服，一个星期都没吃上什么饭，家里每天猪狗朋友一大堆，有一次和他打电话的时候，居然说他朋友在厕所睡着了，哎，这样一帮人在一起还能做什么呢。 现在不一样了，换了个学校，好好读书，还说他做的饭特好吃，也不知道他回去受了什么刺激，反弹那么大。 说实话， 我还挺喜欢那种颓废的男生，叼着烟，在墙角弹着吉他，不常说话。 不过人长大了，知道那样的男生只能看，人还是现实一点好，有些人喜欢找爱自己的，我和我好朋友喜欢找自己爱的，毕竟很少人在恋爱天称上是平衡的，一方付出的越多，一方就容易犯贱。 我怎么写到这里去了呢，越写越乱，下次心定些再写好了', '最近的生活有点乱乱的，整天也不知道到在做什么，刚刚才看完朋友写的文章，我横看竖看也都不敢相信那样颓废的人也有这样的文笔，看了以后，对他多少也有些了解。前几天，他刚从中国回来，还居然帮我带了一样东西，一开始我到还挺新奇问他是什么，他的答案也是我没有估计到的，原来是个护身符，还是特地去山上找什么法师开光的，听起来有那么点小感动，可惜的是。。。我是一个基督徒，不过我也不好，从头到尾都没和他说过。 那天晚上和他小聊了一会儿，这个人还真能带惊喜，没想到他回国一下，整个人都不一样了，以前从不打工，不做饭， 两个月才去干洗店洗一下衣服，一个星期都没吃上什么饭，家里每天猪狗朋友一大堆，有一次和他打电话的时候，居然说他朋友在厕所睡着了，哎，这样一帮人在一起还能做什么呢。 现在不一样了，换了个学校，好好读书，还说他做的饭特好吃，也不知道他回去受了什么刺激，反弹那么大。 说实话， 我还挺喜欢那种颓废的男生，叼着烟，在墙角弹着吉他，不常说话。 不过人长大了，知道那样的男生只能看，人还是现实一点好，有些人喜欢找爱自己的，我和我好朋友喜欢找自己爱的，毕竟很少人在恋爱天称上是平衡的，一方付出的越多，一方就容易犯贱。 我怎么写到这里去了呢，越写越乱，下次心定些再写好了', '鱼说：“你看不到我的眼泪，因为我活在水中。”

 水说：“我能感觉你的眼泪，因为我活在你的心中。', '2003-02-06 11:35:00', 5, '20030312132238_bbsid_195563_board_7_48a7633ad9.html', '20030312132238');
